INSERT INTO tourist_destinations (slug, name, description, destination_type, category_id, province_id, province_name, district_id, district_name, latitude, longitude, altitude_meters, difficulty_level, best_season, entry_fee_npr, visit_duration, is_popular, is_featured, created_at) VALUES
-- Province 1: Koshi Province
('ilam-tea-garden', 'Ilam Tea Garden', 'One of Nepal''s most picturesque tea estates, Ilam Tea Garden stretches across rolling green hills in eastern Nepal. The lush rows of tea plants set against the backdrop of Kanchenjunga offer stunning panoramic views and a serene atmosphere for visitors.', 'NATURE', 1, 1, 'Koshi', 1, 'Ilam', 26.9132, 87.9264, 1200, 'EASY', 'SPRING', 0, '3-4 hours', true, true, NOW()),
('kanchenjunga-base-camp', 'Kanchenjunga Base Camp', 'The base camp trek to the world''s third-highest mountain is one of Nepal''s most rewarding and remote trekking experiences. The route passes through diverse ecosystems from subtropical forests to alpine meadows with spectacular views of Kanchenjunga and surrounding peaks.', 'ADVENTURE', 2, 1, 'Koshi', 2, 'Taplejung', 27.7025, 88.1475, 5143, 'CHALLENGING', 'SPRING', 3000, '14-18 days', true, true, NOW()),
('pathibhara-temple', 'Pathibhara Temple', 'A sacred Hindu temple perched atop a hill at 3,794 meters, Pathibhara is a major pilgrimage site for both Hindu and Buddhist devotees. The temple offers breathtaking panoramic views of Kanchenjunga, Makalu, and the eastern Himalayan range.', 'RELIGIOUS', 3, 1, 'Koshi', 2, 'Taplejung', 27.5567, 87.7167, 3794, 'MODERATE', 'SPRING', 0, '1-2 days', false, false, NOW()),
('kanyam-tea-garden', 'Kanyam Tea Garden', 'A sprawling tea estate in Jhapa district known for its beautiful landscape and tea production. The area offers a peaceful retreat with lush greenery and is a popular weekend getaway for locals and tourists alike.', 'NATURE', 1, 1, 'Koshi', 3, 'Jhapa', 26.5447, 87.9214, 150, 'EASY', 'AUTUMN', 0, '2-3 hours', false, false, NOW()),
('dhankuta-bazaar', 'Dhankuta Bazaar', 'A charming hill town that serves as the headquarters of Dhankuta district, offering traditional Newari architecture and panoramic views of the eastern hills. The town is known for its fruit orchards, particularly oranges and mangoes.', 'CULTURAL', 4, 1, 'Koshi', 4, 'Dhankuta', 27.0167, 87.3167, 1150, 'EASY', 'SPRING', 0, '4-5 hours', false, false, NOW()),
('biratnagar-city', 'Biratnagar City', 'Nepal''s second-largest city and a major industrial hub in the Terai region. The city offers a mix of modern amenities and cultural heritage with several temples and parks worth visiting.', 'CULTURAL', 4, 1, 'Koshi', 5, 'Morang', 26.4525, 87.2640, 72, 'EASY', 'WINTER', 0, '3-4 hours', false, false, NOW()),
('bhojpur-town', 'Bhojpur Town', 'A picturesque hill town known for its traditional Nepali culture and stunning mountain views. The town is a gateway to several trekking routes and offers authentic rural Nepali experiences.', 'CULTURAL', 4, 1, 'Koshi', 6, 'Bhojpur', 27.1667, 87.0500, 1200, 'EASY', 'SPRING', 0, '3-4 hours', false, false, NOW()),

-- Province 2: Madhesh Province
('janaki-temple', 'Janaki Temple', 'A stunning three-storied temple dedicated to Goddess Sita (Janaki), built in Rajput and Mughal architectural styles. The temple is a major pilgrimage site and hosts the famous Vivah Panchami festival celebrating the marriage of Ram and Sita.', 'RELIGIOUS', 3, 2, 'Madhesh', 7, 'Janakpur', 26.7288, 85.9249, 76, 'EASY', 'WINTER', 50, '2-3 hours', true, true, NOW()),
('ram-mandir-janakpur', 'Ram Mandir Janakpur', 'An ancient temple dedicated to Lord Ram located near Janaki Temple in Janakpur. The temple features beautiful architectural details and is an important spiritual center for Hindu devotees.', 'RELIGIOUS', 3, 2, 'Madhesh', 7, 'Janakpur', 26.7300, 85.9260, 76, 'EASY', 'WINTER', 20, '1-2 hours', false, false, NOW()),
('narayani-river-bar', 'Narayani River Bar', 'The sacred Narayani River flows through Bara district offering scenic beauty and religious significance. The riverbanks are popular for picnics and spiritual activities.', 'NATURE', 1, 2, 'Madhesh', 8, 'Bara', 27.0167, 85.0500, 100, 'EASY', 'WINTER', 0, '3-4 hours', false, false, NOW()),
('chitwan-south', 'Chitwan Southern Terai', 'The southern part of Chitwan district offers vast grasslands and forests teeming with wildlife including rhinos, tigers, and elephants. The area provides excellent opportunities for jungle safaris and wildlife photography.', 'WILDLIFE', 5, 2, 'Madhesh', 9, 'Parsa', 27.5833, 84.5000, 150, 'EASY', 'WINTER', 2000, '1-2 days', true, false, NOW()),

-- Province 3: Bagmati Province
('kathmandu-durbar-square', 'Kathmandu Durbar Square', 'The historic royal palace complex in the heart of old Kathmandu, featuring stunning Newari architecture with intricately carved wooden windows and pagoda-style temples. A UNESCO World Heritage Site that showcases Nepal''s rich cultural heritage.', 'HERITAGE', 6, 3, 'Bagmati', 10, 'Kathmandu', 27.7041, 85.3076, 1400, 'EASY', 'AUTUMN', 1000, '3-4 hours', true, true, NOW()),
('swayambhunath', 'Swayambhunath', 'An ancient Buddhist stupa perched atop a hill, also known as the Monkey Temple due to the large number of monkeys living in the area. The stupa offers panoramic views of Kathmandu Valley and is one of the most sacred Buddhist sites in Nepal.', 'RELIGIOUS', 3, 3, 'Bagmati', 10, 'Kathmandu', 27.7149, 85.2894, 1400, 'EASY', 'AUTUMN', 200, '2-3 hours', true, true, NOW()),
('boudhanath', 'Boudhanath', 'One of the largest stupas in the world and a UNESCO World Heritage Site, Boudhanath is a spiritual center for Tibetan Buddhism in Nepal. The stupa is surrounded by monasteries and is a hub of Buddhist culture and meditation.', 'RELIGIOUS', 3, 3, 'Bagmati', 10, 'Kathmandu', 27.7215, 85.3620, 1400, 'EASY', 'AUTUMN', 50, '2-3 hours', true, true, NOW()),
('pashupatinath', 'Pashupatinath Temple', 'Nepal''s most sacred Hindu temple dedicated to Lord Shiva, located on the banks of the Bagmati River. The temple complex includes numerous smaller temples, ashrams, and the famous cremation ghats where Hindu funeral rites are performed.', 'RELIGIOUS', 3, 3, 'Bagmati', 10, 'Kathmandu', 27.7107, 85.3486, 1400, 'EASY', 'AUTUMN', 1000, '3-4 hours', true, true, NOW()),
('thamel', 'Thamel', 'Kathmandu''s most popular tourist district, a vibrant neighborhood filled with shops, restaurants, hotels, and nightlife. The area is a hub for backpackers and offers everything from traditional Nepali handicrafts to modern amenities.', 'CULTURAL', 4, 3, 'Bagmati', 10, 'Kathmandu', 27.7120, 85.3120, 1400, 'EASY', 'AUTUMN', 0, '4-6 hours', true, true, NOW()),
('garden-of-dreams', 'Garden of Dreams', 'A beautifully restored neo-classical garden in the heart of Kathmandu, offering a peaceful oasis away from the bustling city. The garden features fountains, tiered pavilions, and lush greenery perfect for relaxation.', 'NATURE', 1, 3, 'Bagmati', 10, 'Kathmandu', 27.7110, 85.3100, 1400, 'EASY', 'SPRING', 200, '1-2 hours', false, true, NOW()),
('narayanhiti-museum', 'Narayanhiti Palace Museum', 'The former royal palace of Nepal, now a museum showcasing the history and artifacts of the Nepali monarchy. The palace features stunning architecture and offers guided tours of its many halls and rooms.', 'HERITAGE', 6, 3, 'Bagmati', 10, 'Kathmandu', 27.7150, 85.3180, 1400, 'EASY', 'AUTUMN', 500, '2-3 hours', false, false, NOW()),
('patan-durbar-square', 'Patan Durbar Square', 'The ancient royal palace of the Malla kings of Lalitpur, featuring exquisite Newari architecture with carved wooden columns and stone sculptures. A UNESCO World Heritage Site with numerous temples and courtyards.', 'HERITAGE', 6, 3, 'Bagmati', 11, 'Lalitpur', 27.6726, 85.3256, 1400, 'EASY', 'AUTUMN', 1000, '3-4 hours', true, true, NOW()),
('bhaktapur-durbar-square', 'Bhaktapur Durbar Square', 'The best-preserved medieval city in Nepal, featuring stunning architecture including the famous 55-Window Palace and Nyatapola Temple. The entire city is a living museum of Newari culture and craftsmanship.', 'HERITAGE', 6, 3, 'Bagmati', 12, 'Bhaktapur', 27.6710, 85.4282, 1400, 'EASY', 'AUTUMN', 500, '4-5 hours', true, true, NOW()),
('nagarkot', 'Nagarkot', 'A popular hill station offering spectacular sunrise views of the Himalayan range including Mount Everest on clear days. Located at 2,175 meters, it provides a cool retreat from Kathmandu with numerous resorts and viewpoints.', 'NATURE', 1, 3, 'Bagmati', 12, 'Bhaktapur', 27.7172, 85.5167, 2175, 'EASY', 'AUTUMN', 100, '4-6 hours', true, true, NOW()),
('changu-narayan', 'Changu Narayan Temple', 'The oldest temple in Kathmandu Valley, a UNESCO World Heritage Site dating back to the 4th century. The temple features exquisite stone, wood, and metal carvings and is dedicated to Lord Vishnu.', 'RELIGIOUS', 3, 3, 'Bagmati', 12, 'Bhaktapur', 27.7102, 85.4293, 1540, 'EASY', 'AUTUMN', 100, '2-3 hours', false, true, NOW()),
('godavari', 'Godavari', 'A sacred site with a beautiful botanical garden and ancient temples, located at the base of Phulchoki Hill. The area is known for its natural beauty, spiritual significance, and the famous Godavari Spring Festival.', 'RELIGIOUS', 3, 3, 'Bagmati', 11, 'Lalitpur', 27.5950, 85.3760, 1500, 'EASY', 'SPRING', 100, '3-4 hours', false, false, NOW()),
('pharping', 'Pharping', 'A sacred Buddhist and Hindu site at the southern edge of Kathmandu Valley, known for its ancient monasteries, caves, and the famous Asura Cave where Guru Rinpoche attained enlightenment.', 'RELIGIOUS', 3, 3, 'Bagmati', 11, 'Lalitpur', 27.5900, 85.2830, 1500, 'EASY', 'SPRING', 50, '3-4 hours', false, false, NOW()),
('shivapuri-national-park', 'Shivapuri National Park', 'A protected area on the northern rim of Kathmandu Valley offering hiking trails through lush forests with diverse wildlife. The park provides stunning views of the valley and is home to Shivaratri Temple at its summit.', 'NATURE', 1, 3, 'Bagmati', 10, 'Kathmandu', 27.8000, 85.3800, 2762, 'MODERATE', 'SPRING', 300, '4-6 hours', false, false, NOW()),
('taudaha-lake', 'Taudaha Lake', 'A small but culturally significant lake at the southern edge of Kathmandu Valley, believed to be the home of the mythical serpent king Karkotak. The lake is an important site for snake worship and bird watching.', 'NATURE', 1, 3, 'Bagmati', 13, 'Kavrepalanchok', 27.5800, 85.2900, 1200, 'EASY', 'SPRING', 0, '2-3 hours', false, false, NOW()),
('dhulikhel', 'Dhulikhel', 'A charming Newari town offering panoramic views of the Himalayan range from Langtang to Everest. The town features traditional architecture, ancient temples, and excellent hiking trails through terraced hillsides.', 'CULTURAL', 4, 3, 'Bagmati', 13, 'Kavrepalanchok', 27.6203, 85.5533, 1550, 'EASY', 'AUTUMN', 0, '4-6 hours', true, true, NOW()),
('panauti', 'Panauti', 'One of the oldest settlements in Nepal, a beautifully preserved medieval town at the confluence of two sacred rivers. The town features stunning Newari architecture with ancient temples and traditional courtyards.', 'CULTURAL', 4, 3, 'Bagmati', 13, 'Kavrepalanchok', 27.5750, 85.5170, 1400, 'EASY', 'AUTUMN', 0, '3-4 hours', false, false, NOW()),
('tarkeghyang', 'Tarkeghyang', 'A traditional Sherpa village in Sindhupalchok district known for its ancient monasteries and traditional architecture. The village offers authentic cultural experiences and stunning mountain views.', 'CULTURAL', 4, 3, 'Bagmati', 14, 'Sindhupalchok', 27.9500, 85.8500, 2600, 'MODERATE', 'SPRING', 0, '4-5 hours', false, false, NOW()),
('charikot', 'Charikot', 'A scenic hill town in Dolakha district offering stunning views of Langtang and Ganesh Himal ranges. The town is a gateway to several trekking routes and traditional Sherpa villages.', 'NATURE', 1, 3, 'Bagmati', 15, 'Dolakha', 27.6833, 86.1167, 1940, 'EASY', 'SPRING', 0, '3-4 hours', false, false, NOW()),
('dolakha-bhimsen', 'Dolakha Bhimsen Temple', 'An ancient temple dedicated to Lord Bhimsen, one of the five Pandava brothers from the Mahabharata. The temple is famous for the miraculous idol that continuously sweats milk-like liquid.', 'RELIGIOUS', 3, 3, 'Bagmati', 15, 'Dolakha', 27.6667, 86.1000, 1900, 'EASY', 'AUTUMN', 0, '2-3 hours', false, false, NOW()),

-- Province 4: Gandaki Province
('phewa-lake', 'Phewa Lake', 'Nepal''s second-largest lake and the centerpiece of Pokhara, surrounded by mountains and lush forests. The lake is perfect for boating, and the Tal Barahi Temple situated on an island in the middle is a major attraction.', 'NATURE', 1, 4, 'Gandaki', 16, 'Kaski', 28.2096, 83.9500, 790, 'EASY', 'AUTUMN', 100, '3-4 hours', true, true, NOW()),
('sarangkot', 'Sarangkot', 'The most popular viewpoint in Pokhara for watching sunrise over the Annapurna and Dhaulagiri ranges. Located at 1,592 meters, it offers stunning panoramic views of the Himalayas and the valley below.', 'NATURE', 1, 4, 'Gandaki', 16, 'Kaski', 28.2436, 83.9547, 1592, 'EASY', 'AUTUMN', 50, '2-3 hours', true, true, NOW()),
('world-peace-pagoda-pokhara', 'World Peace Pagoda Pokhara', 'A magnificent Buddhist stupa located on a hilltop south of Pokhara, offering panoramic views of the Annapurna range, Phewa Lake, and the city. The stupa is one of many World Peace Pagodas built around the world.', 'RELIGIOUS', 3, 4, 'Gandaki', 16, 'Kaski', 28.1967, 83.9667, 1100, 'MODERATE', 'AUTUMN', 0, '3-4 hours', true, false, NOW()),
('davis-falls', 'Davis Falls', 'A unique waterfall where the water flows into an underground cavern, creating a spectacular natural phenomenon. The falls are named after a Swiss tourist who tragically fell into the waterfall in 1961.', 'NATURE', 1, 4, 'Gandaki', 16, 'Kaski', 28.1900, 83.9800, 800, 'EASY', 'ALL_YEAR', 50, '1-2 hours', true, false, NOW()),
('gupteshwor-cave', 'Gupteshwor Cave', 'A sacred cave temple near Davis Falls containing a natural Shiva lingam and stunning stalactite formations. The cave is an important religious site and offers a mystical experience for visitors.', 'RELIGIOUS', 3, 4, 'Gandaki', 16, 'Kaski', 28.1890, 83.9810, 800, 'EASY', 'ALL_YEAR', 50, '1-2 hours', true, false, NOW()),
('tal-barahi-temple', 'Tal Barahi Temple', 'A two-storied pagoda temple situated on an island in the middle of Phewa Lake, dedicated to the goddess Taleju Bhawani. The temple is accessible only by boat and is a major religious and tourist site.', 'RELIGIOUS', 3, 4, 'Gandaki', 16, 'Kaski', 28.2050, 83.9600, 790, 'EASY', 'AUTUMN', 0, '2-3 hours', true, false, NOW()),
('begnas-lake', 'Begnas Lake', 'The third-largest lake in Nepal, located east of Pokhara, offering a more peaceful alternative to Phewa Lake. The lake is surrounded by hills and farmland, making it ideal for fishing and bird watching.', 'NATURE', 1, 4, 'Gandaki', 16, 'Kaski', 28.2500, 84.0833, 790, 'EASY', 'SPRING', 0, '2-3 hours', false, false, NOW()),
('rupa-lake', 'Rupa Lake', 'A serene lake near Pokhara known for its peaceful atmosphere and beautiful surroundings. The lake is less crowded than Phewa and offers excellent opportunities for kayaking and nature walks.', 'NATURE', 1, 4, 'Gandaki', 16, 'Kaski', 28.2333, 84.0500, 790, 'EASY', 'SPRING', 0, '2-3 hours', false, false, NOW()),
('international-mountain-museum', 'International Mountain Museum', 'A museum in Pokhara dedicated to the mountains of Nepal and mountaineering history. The museum features exhibits on the geology, culture, and history of Himalayan climbing with artifacts and photographs.', 'HERITAGE', 6, 4, 'Gandaki', 16, 'Kaski', 28.1950, 83.9750, 800, 'EASY', 'ALL_YEAR', 300, '2-3 hours', false, false, NOW()),
('seti-river-gorge', 'Seti River Gorge', 'A dramatic river gorge carved by the Seti River through the mountains near Pokhara. The gorge offers stunning views and is a popular spot for white-water rafting and nature walks.', 'NATURE', 1, 4, 'Gandaki', 16, 'Kaski', 28.2200, 83.9700, 800, 'EASY', 'AUTUMN', 0, '2-3 hours', false, false, NOW()),
('muktinath', 'Muktinath', 'A sacred pilgrimage site for both Hindus and Buddhists, located at 3,710 meters in the Mustang district. The temple features 108 water spouts and is one of the highest-altitude temples in the world.', 'RELIGIOUS', 3, 4, 'Gandaki', 17, 'Mustang', 28.8167, 83.8667, 3710, 'MODERATE', 'SPRING', 100, '1-2 days', true, true, NOW()),
('lo-manthang', 'Lo Manthang', 'The ancient walled capital of the Kingdom of Mustang, a UNESCO World Heritage Site featuring traditional Tibetan architecture and culture. The town preserves medieval Tibetan Buddhist monasteries and royal palaces.', 'HERITAGE', 6, 4, 'Gandaki', 17, 'Mustang', 29.1833, 83.9500, 3810, 'MODERATE', 'SPRING', 5000, '2-3 days', true, true, NOW()),
('jomsom', 'Jomsom', 'A major transit point for Mustang treks and the gateway to Upper Mustang and Muktinath. The town sits in a dramatic landscape of eroded cliffs and the Kali Gandaki riverbed.', 'CULTURAL', 4, 4, 'Gandaki', 17, 'Mustang', 28.7833, 83.7333, 2720, 'EASY', 'SPRING', 0, '1-2 days', false, false, NOW()),
('kagbeni', 'Kagbeni', 'A medieval village at the confluence of the Kali Gandaki and Krishna Gandaki rivers, serving as the gateway to Upper Mustang. The village features ancient stone buildings and a 15th-century monastery.', 'CULTURAL', 4, 4, 'Gandaki', 17, 'Mustang', 28.8333, 83.7833, 2810, 'MODERATE', 'SPRING', 0, '1 day', false, true, NOW()),
('thorong-la-pass', 'Thorong La Pass', 'The highest point of the Annapurna Circuit trek at 5,416 meters, offering breathtaking views of the Annapurna and Dhaulagiri ranges. The pass is a challenging but rewarding section of one of the world''s classic treks.', 'ADVENTURE', 2, 4, 'Gandaki', 18, 'Manang', 28.8000, 83.8167, 5416, 'CHALLENGING', 'SPRING', 0, '1 day', true, true, NOW()),
('tilicho-lake', 'Tilicho Lake', 'One of the highest lakes in the world at 4,919 meters, surrounded by towering peaks and glaciers. The lake is a popular side trip from the Annapurna Circuit and offers spectacular alpine scenery.', 'NATURE', 1, 4, 'Gandaki', 18, 'Manang', 28.6833, 83.8500, 4919, 'CHALLENGING', 'SPRING', 0, '2-3 days', true, true, NOW()),
('ice-lake-manang', 'Ice Lake Manang', 'A stunning glacial lake at 4,600 meters near Manang village, offering spectacular views of the Annapurna range. The trek to the lake passes through beautiful alpine landscapes and yak pastures.', 'NATURE', 1, 4, 'Gandaki', 18, 'Manang', 28.6667, 84.0167, 4600, 'CHALLENGING', 'SPRING', 0, '1 day', false, false, NOW()),
('gangapurna-lake', 'Gangapurna Lake', 'A beautiful glacial lake near Manang village with stunning reflections of Gangapurna Peak. The lake is easily accessible and offers excellent photography opportunities with its turquoise waters.', 'NATURE', 1, 4, 'Gandaki', 18, 'Manang', 28.6500, 84.0333, 4300, 'MODERATE', 'SPRING', 0, '3-4 hours', false, false, NOW()),
('gorkha-durbar', 'Gorkha Durbar', 'The historic palace of the Shah dynasty and the birthplace of King Prithvi Narayan Shah who unified Nepal. The palace sits atop a hill offering panoramic views and features impressive architecture and royal artifacts.', 'HERITAGE', 6, 4, 'Gandaki', 19, 'Gorkha', 28.0000, 84.6333, 1100, 'EASY', 'AUTUMN', 100, '3-4 hours', true, true, NOW()),
('bandipur', 'Bandipur', 'A beautifully preserved Newari hilltop town offering stunning views of the Himalayan range and the Terai plains. The town features traditional architecture, ancient temples, and a vibrant cultural atmosphere.', 'CULTURAL', 4, 4, 'Gandaki', 20, 'Tanahu', 27.9348, 84.4087, 1030, 'EASY', 'AUTUMN', 0, '4-6 hours', true, true, NOW()),
('manakamana-temple', 'Manakamana Temple', 'A sacred Hindu temple dedicated to Goddess Bhagwati, accessible by cable car offering spectacular mountain views. The temple is believed to fulfill the wishes of devotees who visit with pure hearts.', 'RELIGIOUS', 3, 4, 'Gandaki', 20, 'Tanahu', 27.9167, 84.7833, 1300, 'EASY', 'AUTUMN', 500, '4-6 hours', true, false, NOW()),

-- Province 5: Lumbini Province
('lumbini-sacred-garden', 'Lumbini Sacred Garden', 'The birthplace of Lord Buddha and a UNESCO World Heritage Site, featuring the sacred garden where Queen Mayadevi gave birth to Siddhartha Gautama. The area includes the Maya Devi Temple, Ashoka Pillar, and numerous monasteries built by Buddhist nations worldwide.', 'HERITAGE', 6, 5, 'Lumbini', 21, 'Rupandehi', 27.4833, 83.2767, 150, 'EASY', 'WINTER', 50, '4-6 hours', true, true, NOW()),
('maya-devi-temple', 'Maya Devi Temple', 'The exact birthplace of Lord Buddha, marked by a marker stone inside the temple. The temple is the most sacred site in Lumbini and attracts pilgrims from around the world.', 'RELIGIOUS', 3, 5, 'Lumbini', 21, 'Rupandehi', 27.4833, 83.2767, 150, 'EASY', 'WINTER', 0, '1-2 hours', true, false, NOW()),
('ashoka-pillar', 'Ashoka Pillar', 'A stone pillar erected by Emperor Ashoka in 249 BC marking the birthplace of Buddha. The pillar is one of the oldest historical monuments in Nepal and bears an inscription confirming Lumbini as Buddha''s birthplace.', 'HERITAGE', 6, 5, 'Lumbini', 21, 'Rupandehi', 27.4833, 83.2770, 150, 'EASY', 'WINTER', 0, '30 minutes', true, false, NOW()),
('lumbini-museum', 'Lumbini Museum', 'A museum showcasing the history and archaeology of Lumbini and the life of Lord Buddha. The museum contains artifacts from the Maurya, Kushan, and Gupta periods discovered during excavations.', 'HERITAGE', 6, 5, 'Lumbini', 21, 'Rupandehi', 27.4850, 83.2750, 150, 'EASY', 'WINTER', 50, '1-2 hours', false, false, NOW()),
('world-peace-pagoda-lumbini', 'World Peace Pagoda Lumbini', 'A beautiful white pagoda-style stupa built by the Japanese Buddhist community as a symbol of world peace. The stupa is one of the most prominent landmarks in the Lumbini development zone.', 'RELIGIOUS', 3, 5, 'Lumbini', 21, 'Rupandehi', 27.4750, 83.2720, 150, 'EASY', 'WINTER', 0, '1-2 hours', false, true, NOW()),
('monastic-zone-lumbini', 'Monastic Zone Lumbini', 'An area within Lumbini containing monasteries built by Buddhist countries from around the world, each showcasing their unique architectural styles. The zone is divided into Eastern (Theravada) and Western (Mahayana) sections.', 'RELIGIOUS', 3, 5, 'Lumbini', 21, 'Rupandehi', 27.4800, 83.2700, 150, 'EASY', 'WINTER', 0, '2-3 hours', false, false, NOW()),
('tansen', 'Tansen', 'A historic hill town and former capital of the Magar kingdom, offering stunning views of the Himalayan range and the Terai plains. The town features traditional architecture, the famous Tansen Dhaka topi (hat), and Rani Mahal.', 'CULTURAL', 4, 5, 'Lumbini', 22, 'Palpa', 27.8667, 83.5400, 1350, 'EASY', 'SPRING', 0, '4-6 hours', true, true, NOW()),
('rani-mahal', 'Rani Mahal', 'A stunning palace built in 1893 by Khadga Shumsher Rana in memory of his wife, often called the ''Nepal Taj Mahal''. The palace is located on the banks of the Kali Gandaki River with beautiful architectural details.', 'HERITAGE', 6, 5, 'Lumbini', 22, 'Palpa', 27.8000, 83.5500, 600, 'MODERATE', 'SPRING', 100, '4-6 hours', true, true, NOW()),
('shreenagar-hill', 'Shreenagar Hill', 'A scenic viewpoint in Tansen offering panoramic views of the Himalayan range and the surrounding hills. The hill is a popular spot for sunrise and sunset views and has several walking trails.', 'NATURE', 1, 5, 'Lumbini', 22, 'Palpa', 27.8700, 83.5500, 1400, 'EASY', 'SPRING', 0, '2-3 hours', false, false, NOW()),

-- Province 6: Karnali Province
('jumla-valley', 'Jumla Valley', 'A remote and beautiful valley in the Karnali region known for its apple orchards and traditional culture. The valley offers stunning mountain views and authentic rural Nepali experiences far from tourist crowds.', 'NATURE', 1, 6, 'Karnali', 23, 'Jumla', 29.2747, 82.1936, 2370, 'MODERATE', 'SPRING', 0, '2-3 days', false, false, NOW()),
('tila-lake-jumla', 'Tila Lake Jumla', 'A beautiful alpine lake in Jumla district surrounded by forests and mountains. The lake is a popular pilgrimage site for Hindus and offers excellent fishing and camping opportunities.', 'NATURE', 1, 6, 'Karnali', 23, 'Jumla', 29.3000, 82.2000, 2800, 'MODERATE', 'SPRING', 0, '1 day', false, false, NOW()),
('shey-phoksundo-lake', 'Shey Phoksundo Lake', 'Nepal''s deepest lake with stunning turquoise waters, located in the remote Dolpa district. The lake is surrounded by dramatic cliffs and is considered sacred by both Buddhist and Bon practitioners.', 'NATURE', 1, 6, 'Karnali', 24, 'Dolpa', 29.2000, 82.9333, 3611, 'CHALLENGING', 'SPRING', 5000, '3-5 days', true, true, NOW()),
('phoksundo-national-park', 'Shey Phoksundo National Park', 'Nepal''s largest national park, home to Shey Phoksundo Lake and diverse wildlife including snow leopards, blue sheep, and Himalayan tahr. The park offers stunning landscapes and ancient Bon culture.', 'NATURE', 1, 6, 'Karnali', 24, 'Dolpa', 29.2000, 82.9333, 3611, 'CHALLENGING', 'SPRING', 5000, '5-7 days', true, true, NOW()),
('simikot', 'Simikot', 'The administrative headquarters of Humla district and a gateway to Mount Kailash in Tibet. The town offers stunning mountain views and is a starting point for high-altitude treks.', 'CULTURAL', 4, 6, 'Karnali', 25, 'Humla', 29.9500, 81.8333, 2950, 'MODERATE', 'SPRING', 0, '2-3 days', false, false, NOW()),
('rara-lake', 'Rara Lake', 'Nepal''s largest lake, a pristine alpine lake at 2,990 meters surrounded by pristine forests and hills. The lake is known for its crystal-clear waters and is a popular trekking destination in the remote western region.', 'NATURE', 1, 6, 'Karnali', 26, 'Mugu', 29.5167, 82.0833, 2990, 'MODERATE', 'SPRING', 3000, '4-6 days', true, true, NOW()),

-- Province 7: Sudurpashchim Province
('shuklaphanta-wildlife-reserve', 'Shuklaphanta Wildlife Reserve', 'A protected area in the western Terai known for its large population of wild elephants and swamp deer. The reserve offers jungle safaris with opportunities to spot tigers, rhinos, and numerous bird species.', 'WILDLIFE', 5, 7, 'Sudurpashchim', 27, 'Kanchanpur', 28.8000, 80.2000, 150, 'EASY', 'WINTER', 2000, '1-2 days', false, true, NOW()),
('mahakali-temple', 'Mahakali Temple', 'A sacred temple dedicated to Goddess Mahakali located near the Mahakali River at the westernmost point of Nepal. The temple is an important pilgrimage site and offers views of the India-Nepal border.', 'RELIGIOUS', 3, 7, 'Sudurpashchim', 27, 'Kanchanpur', 28.9500, 80.1000, 200, 'EASY', 'WINTER', 0, '2-3 hours', false, false, NOW()),
('api-himal-views', 'Api Himal Views', 'Spectacular mountain views of Api Himal, the highest peak in far-western Nepal at 7,132 meters. The area offers pristine wilderness and traditional Bhotia culture far from mainstream tourism.', 'NATURE', 1, 7, 'Sudurpashchim', 28, 'Baitadi', 29.9500, 80.9333, 2500, 'MODERATE', 'SPRING', 0, '2-3 days', false, false, NOW()),
('dasharathchand', 'Dasharathchand', 'The headquarters of Baitadi district, a scenic town offering views of the Mahakali River and surrounding hills. The town serves as a base for treks to Api Himal and other remote areas.', 'CULTURAL', 4, 7, 'Sudurpashchim', 28, 'Baitadi', 29.5500, 80.6000, 1200, 'EASY', 'SPRING', 0, '3-4 hours', false, false, NOW()),
('lipulekh-pass', 'Lipulekh Pass', 'A high-altitude mountain pass at 5,334 meters on the border between Nepal and Tibet, used as a trade route for centuries. The pass offers stunning views of the Himalayan range and access to Mount Kailash.', 'ADVENTURE', 2, 7, 'Sudurpashchim', 29, 'Darchula', 30.2500, 80.5333, 5334, 'CHALLENGING', 'SPRING', 0, '8-10 days', false, false, NOW()),
('dhangadhi', 'Dhangadhi', 'The largest city in far-western Nepal, a major commercial center and gateway to the western Terai. The city offers modern amenities and serves as a base for exploring the western region.', 'CULTURAL', 4, 7, 'Sudurpashchim', 26, 'Kailali', 28.7000, 80.5833, 109, 'EASY', 'WINTER', 0, '3-4 hours', false, false, NOW());
